const swiperLp=new Swiper(".p-logo-slider__swiper",{loop:!0,slidesPerView:.4,speed:4e4,allowTouchMove:!1,autoplay:{delay:0},breakpoints:{768:{slidesPerView:1}}});let voiceSwiper;const swiperInit=()=>{window.innerWidth<=768&&!voiceSwiper?voiceSwiper=new Swiper(".p-lp-voice__slider",{loop:!0,slidesPerView:1.2,spaceBetween:17,centeredSlides:!0,navigation:{nextEl:".swiper-button-next",prevEl:".swiper-button-prev"}}):768<window.innerWidth&&voiceSwiper&&(voiceSwiper.destroy(!0,!0),voiceSwiper=null)};swiperInit(),window.addEventListener("resize",swiperInit);